    JP:'ja',
    KR:'ko',
    CN:'zh',TW:'zh',HK:'zh',SG:'zh',
    AE:'ar',SA:'ar',MA:'ar',DZ:'ar',EG:'ar',TN:'ar',JO:'ar',QA:'ar',KW:'ar',BH:'ar',OM:'ar',YE:'ar',IQ:'ar',LB:'ar',LY:'ar',SD:'ar',SO:'ar',DJ:'ar',MR:'ar',
